cat > /tmp/inspect_types.cs << 'EOF'
using System;
using System.Reflection;
using System.Linq;

var assemblyPath = args[0];
try
{
    var assembly = Assembly.LoadFrom(assemblyPath);
    var types = assembly.GetTypes()
        .Where(t => t.IsPublic)
        .GroupBy(t => t.Namespace)
        .OrderBy(g => g.Key);

    foreach (var ns in types)
    {
        Console.WriteLine($"\n=== {ns.Key ?? "Global"} ===");
        foreach (var type in ns.OrderBy(t => t.Name))
        {
            string typeKind = type.IsInterface ? "interface" : 
                            type.IsAbstract ? "abstract class" : 
                            type.IsValueType ? "struct" : 
                            type.IsEnum ? "enum" : "class";
            Console.WriteLine($"  {typeKind} {type.Name}");

            // Show key methods for important types
            if (type.Name.Contains("Builder") || type.Name.Contains("Factory") || type.Name.Contains("Client") || 
                type.Name.Contains("ChatClient") || type.Name.Contains("Agent"))
            {
                var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                    .Where(m => !m.IsSpecialName)
                    .Take(10);
                foreach (var method in methods)
                {
                    var parms = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"      {method.ReturnType.Name} {method.Name}({parms})");
                }
            }
        }
    }
}
catch (Exception ex)
{
    Console.WriteLine($"Error: {ex.Message}");
}
EOF

