using System;
using System.Reflection;
using System.Linq;

string[] assemblies = new[]
{
    "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.4.0/lib/net9.0/Microsoft.Extensions.AI.Abstractions.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai/10.4.0/lib/net9.0/Microsoft.Extensions.AI.dll",
    "/home/runner/.nuget/packages/microsoft.extensions.ai.openai/10.4.1/lib/net9.0/Microsoft.Extensions.AI.OpenAI.dll",
    "/home/runner/.nuget/packages/microsoft.agents.ai/1.0.0/lib/net9.0/Microsoft.Agents.AI.dll",
    "/home/runner/.nuget/packages/microsoft.agents.ai.abstractions/1.0.0/lib/net9.0/Microsoft.Agents.AI.Abstractions.dll",
    "/home/runner/.nuget/packages/openai/2.9.1/lib/net8.0/OpenAI.dll"
};

foreach (var path in assemblies)
{
    try
    {
        var assembly = Assembly.LoadFrom(path);
        Console.WriteLine($"\n{'='*80}");
        Console.WriteLine($"ASSEMBLY: {assembly.GetName().Name} v{assembly.GetName().Version}");
        Console.WriteLine($"{'='*80}");

        var typesByNamespace = assembly.GetTypes()
            .Where(t => t.IsPublic)
            .GroupBy(t => t.Namespace ?? "<Global>")
            .OrderBy(g => g.Key);

        foreach (var ns in typesByNamespace)
        {
            Console.WriteLine($"\n[{ns.Key}]");
            foreach (var type in ns.OrderBy(t => t.Name))
            {
                string typeKind = type.IsInterface ? "I " : 
                                type.IsAbstract ? "A " : 
                                type.IsValueType ? "S " : 
                                type.IsEnum ? "E " : "C ";
                Console.WriteLine($"  {typeKind}{type.Name}");

                // Show key public methods/properties for important types
                if (type.Name.Contains("Builder") || type.Name.Contains("Factory") || type.Name.Contains("Client") || 
                    type.Name.Contains("Agent") || type.Name.Contains("Function") || type.Name.Contains("Message"))
                {
                    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                        .Where(m => !m.IsSpecialName && m.DeclaringType == type)
                        .Take(8);

                    if (methods.Any())
                    {
                        foreach (var method in methods)
                        {
                            var parms = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                            Console.WriteLine($"      {method.ReturnType.Name} {method.Name}({parms})");
                        }
                    }

                    // Show properties
                    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance)
                        .Where(p => p.DeclaringType == type)
                        .Take(5);

                    if (props.Any())
                    {
                        foreach (var prop in props)
                        {
                            Console.WriteLine($"      {prop.PropertyType.Name} {prop.Name} {{ get; {(prop.CanWrite ? "set; " : "")}}}");
                        }
                    }
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"ERROR loading {path}: {ex.Message}");
    }
}
EOF
